import { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Progress } from "@/components/ui/progress";
import { Checkbox } from "@/components/ui/checkbox";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { toast } from "sonner";
import {
  Loader2, MapPin, AlertTriangle, CheckCircle2, Trash2, RefreshCw,
  Shield, AlertCircle, ImageIcon, BookOpen, FileWarning, Copy, ExternalLink, Star, Play, Sparkles, Wrench,
} from "lucide-react";

interface DataIssue {
  id: string;
  name: string;
  name_en?: string;
  address: string;
  lat: number;
  lng: number;
  template?: string;
  image_url?: string | null;
  issue_type?: string;
  duplicate_count?: number;
  google_place_id?: string;
  created_at?: string;
  missing_story?: boolean;
  missing_photo?: boolean;
  missing_description?: boolean;
  missing_iching?: boolean;
}

interface DuplicateGroup {
  key: string;
  items: DataIssue[];
  keepId: string; // The ID we recommend keeping
}

interface CheckStats {
  total: number;
  invalid_address_count: number;
  invalid_name_count: number;
  zero_coords_count: number;
  duplicate_count: number;
  incomplete_count: number;
  no_story_count: number;
  no_photo_count: number;
  no_iching_count: number;
}

/** Pick the best record to keep in a duplicate group */
function pickBestRecord(items: DataIssue[]): string {
  // Priority: has google_place_id > has image > longest address > newest
  const scored = items.map(item => ({
    id: item.id,
    score:
      (item.google_place_id ? 1000 : 0) +
      (item.image_url ? 100 : 0) +
      (item.address?.length || 0) +
      (item.created_at ? new Date(item.created_at).getTime() / 1e12 : 0),
  }));
  scored.sort((a, b) => b.score - a.score);
  return scored[0].id;
}

export default function DataCheckPanel() {
  const { t } = useTranslation();
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("location");
  const [stats, setStats] = useState<CheckStats | null>(null);
  const [invalidAddresses, setInvalidAddresses] = useState<DataIssue[]>([]);
  const [zeroCoords, setZeroCoords] = useState<DataIssue[]>([]);
  const [duplicates, setDuplicates] = useState<DataIssue[]>([]);
  const [incomplete, setIncomplete] = useState<DataIssue[]>([]);
  const [invalidNames, setInvalidNames] = useState<DataIssue[]>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isDeleting, setIsDeleting] = useState(false);
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichProgress, setEnrichProgress] = useState({ current: 0, total: 0 });
  const [confirmDialog, setConfirmDialog] = useState<{
    open: boolean;
    title: string;
    description: string;
    onConfirm: () => void;
  }>({ open: false, title: "", description: "", onConfirm: () => {} });

  // Group duplicates by name+coords OR by matching address
  const duplicateGroups = useMemo<DuplicateGroup[]>(() => {
    // Build a union-find to merge items sharing name+coords OR address
    const parent = new Map<string, string>();
    const find = (id: string): string => {
      if (!parent.has(id)) parent.set(id, id);
      if (parent.get(id) !== id) parent.set(id, find(parent.get(id)!));
      return parent.get(id)!;
    };
    const union = (a: string, b: string) => {
      const ra = find(a), rb = find(b);
      if (ra !== rb) parent.set(ra, rb);
    };

    // Group by name+coords
    const byNameCoord = new Map<string, string[]>();
    for (const item of duplicates) {
      const key = `${(item.name_en || item.name || "").toLowerCase()}|${item.lat}|${item.lng}`;
      if (!byNameCoord.has(key)) byNameCoord.set(key, []);
      byNameCoord.get(key)!.push(item.id);
    }
    for (const ids of byNameCoord.values()) {
      for (let i = 1; i < ids.length; i++) union(ids[0], ids[i]);
    }

    // Group by normalized address
    const byAddr = new Map<string, string[]>();
    for (const item of duplicates) {
      const addr = (item.address || "").toLowerCase().trim();
      if (addr.length > 10) {
        if (!byAddr.has(addr)) byAddr.set(addr, []);
        byAddr.get(addr)!.push(item.id);
      }
    }
    for (const ids of byAddr.values()) {
      if (ids.length > 1) {
        for (let i = 1; i < ids.length; i++) union(ids[0], ids[i]);
      }
    }

    // Collect groups
    const itemMap = new Map(duplicates.map(d => [d.id, d]));
    const groups = new Map<string, DataIssue[]>();
    for (const item of duplicates) {
      const root = find(item.id);
      if (!groups.has(root)) groups.set(root, []);
      groups.get(root)!.push(item);
    }

    return Array.from(groups.values())
      .filter(items => items.length > 1)
      .map(items => ({
        key: items.map(i => i.id).join("|"),
        items: items.sort((a, b) => {
          const aScore = (a.google_place_id ? 1000 : 0) + (a.image_url ? 100 : 0);
          const bScore = (b.google_place_id ? 1000 : 0) + (b.image_url ? 100 : 0);
          return bScore - aScore;
        }),
        keepId: pickBestRecord(items),
      }));
  }, [duplicates]);

  // Kept IDs set
  const keptIds = useMemo(() => new Set(duplicateGroups.map(g => g.keepId)), [duplicateGroups]);

  const [repairFilter, setRepairFilter] = useState<string | null>(null);

  // Combined address + coords + name issues (deduplicated by id) — unified "repair" tab
  const repairIssues = useMemo(() => {
    const seen = new Set<string>();
    const combined: DataIssue[] = [];
    for (const item of [...invalidAddresses, ...zeroCoords, ...invalidNames]) {
      if (!seen.has(item.id)) {
        seen.add(item.id);
        const isZeroCoord = item.lat === 0 && item.lng === 0;
        combined.push({
          ...item,
          issue_type: item.issue_type || (isZeroCoord ? 'zero_coords' : undefined),
        });
      }
    }
    return combined;
  }, [invalidAddresses, zeroCoords, invalidNames]);

  // Count issues by type for filter chips
  const repairIssueTypeCounts = useMemo(() => {
    const counts = new Map<string, number>();
    for (const item of repairIssues) {
      const type = item.issue_type || 'unknown';
      counts.set(type, (counts.get(type) || 0) + 1);
    }
    return counts;
  }, [repairIssues]);

  // Filtered repair issues
  const filteredRepairIssues = useMemo(() => {
    if (!repairFilter) return repairIssues;
    return repairIssues.filter(item => (item.issue_type || 'unknown') === repairFilter);
  }, [repairIssues, repairFilter]);

  const runCheck = async (checkType: string = "all") => {
    setIsLoading(true);
    setSelectedIds(new Set());
    try {
      const { data, error } = await supabase.rpc("check_data_quality", {
        p_check_type: checkType,
        p_limit: 200,
        p_offset: 0,
      });
      if (error) throw error;
      const result = data as any;
      if (result.error) throw new Error(result.error);
      setStats(result.stats);
      if (result.invalid_address) setInvalidAddresses(result.invalid_address);
      if (result.zero_coords) setZeroCoords(result.zero_coords);
      if (result.duplicates) setDuplicates(result.duplicates);
      if (result.incomplete) setIncomplete(result.incomplete);
      if (result.invalid_names) setInvalidNames(result.invalid_names);
      toast.success(t("toast.dataCheckComplete"));
    } catch (e: any) {
      const msg = e?.message || e?.details || e?.hint || JSON.stringify(e);
      toast.error(t("toast.checkFailed", { message: msg }));
    } finally {
      setIsLoading(false);
    }
  };

  const executeDelete = async () => {
    setIsDeleting(true);
    let deleted = 0;
    let errors: string[] = [];
    for (const id of selectedIds) {
      const { error } = await supabase.from("restaurants").delete().eq("id", id);
      if (!error) {
        deleted++;
      } else {
        console.error(`Delete failed for ${id}:`, error);
        errors.push(error.message);
      }
    }
    if (deleted > 0) {
      toast.success(`已删除 ${deleted} 条记录`);
    }
    if (errors.length > 0) {
      toast.error(`${errors.length} 条记录删除失败: ${errors[0]}`);
    }
    setSelectedIds(new Set());
    setIsDeleting(false);
    await runCheck("all");
  };

  const showDeleteConfirm = () => {
    setConfirmDialog({
      open: true,
      title: "确认删除",
      description: `确定要删除 ${selectedIds.size} 条记录吗？此操作不可撤销。`,
      onConfirm: () => {
        setConfirmDialog(prev => ({ ...prev, open: false }));
        executeDelete();
      },
    });
  };

  const handleDelete = () => {
    if (selectedIds.size === 0) return;
    // For duplicates tab, warn if any kept items are selected
    if (activeTab === "duplicates") {
      const keepSelected = Array.from(selectedIds).filter(id => keptIds.has(id));
      if (keepSelected.length > 0) {
        setConfirmDialog({
          open: true,
          title: "⚠️ 包含建议保留的记录",
          description: `你选中了 ${keepSelected.length} 个「建议保留」的记录。确定要一起删除吗？取消后可以取消勾选带 ⭐ 标记的记录。`,
          onConfirm: () => {
            setConfirmDialog(prev => ({ ...prev, open: false }));
            // Delay to let the first dialog close before opening the second
            setTimeout(() => showDeleteConfirm(), 150);
          },
        });
        return;
      }
    }
    showDeleteConfirm();
  };

  /** Select all duplicate items EXCEPT the ones marked as "keep" */
  const selectAllDuplicatesExceptKept = () => {
    const allDupIds = duplicates.map(d => d.id);
    const nonKeptSelected = allDupIds.filter(id => !keptIds.has(id));
    const allNonKeptCurrentlySelected = nonKeptSelected.every(id => selectedIds.has(id));

    setSelectedIds(prev => {
      const next = new Set(prev);
      if (allNonKeptCurrentlySelected) {
        // Deselect all
        allDupIds.forEach(id => next.delete(id));
      } else {
        // Select only non-kept
        nonKeptSelected.forEach(id => next.add(id));
      }
      return next;
    });
  };

  const handleEnrichSelected = async (type: "story" | "photo" | "iching" | "auto") => {
    const ids = Array.from(selectedIds);
    if (type === "auto" && ids.length === 0) {
      // Run the auto pipeline without selection
      setIsEnriching(true);
      try {
        const { data, error } = await supabase.functions.invoke("auto-enrich-restaurants");
        if (error) throw error;
        toast.success(`管线完成 - 故事: ${data?.stories_processed || 0}, 照片: ${data?.photos_processed || 0}`);
      } catch (e) {
        toast.error("执行失败: " + (e instanceof Error ? e.message : String(e)));
      } finally {
        setIsEnriching(false);
        await runCheck("all");
      }
      return;
    }
    if (ids.length === 0) return;
    setIsEnriching(true);
    setEnrichProgress({ current: 0, total: ids.length });
    try {
      if (type === "story" || type === "iching") {
        const mode = type === "iching" ? "iching" : "story";
        const batchSize = 5;
        for (let i = 0; i < ids.length; i += batchSize) {
          const batch = ids.slice(i, i + batchSize);
          await supabase.functions.invoke("generate-store-stories", {
            body: { restaurant_ids: batch, mode, no_brand: true },
          });
          setEnrichProgress({ current: Math.min(i + batchSize, ids.length), total: ids.length });
          if (i + batchSize < ids.length) await new Promise(r => setTimeout(r, 2000));
        }
      } else {
        for (let i = 0; i < ids.length; i++) {
          await supabase.functions.invoke("fetch-place-photos", {
            body: { restaurant_ids: [ids[i]], limit: 1, smart_filter: true },
          });
          setEnrichProgress({ current: i + 1, total: ids.length });
          await new Promise(r => setTimeout(r, 500));
        }
      }
      toast.success(`${type === "story" ? "故事" : type === "iching" ? "易经" : "照片"}补全完成`);
    } catch (e) {
      toast.error("补全失败: " + (e instanceof Error ? e.message : String(e)));
    } finally {
      setIsEnriching(false);
      await runCheck("all");
    }
  };

  const toggleId = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const toggleAll = (items: DataIssue[]) => {
    const allIds = items.map(i => i.id);
    const allSelected = allIds.every(id => selectedIds.has(id));
    setSelectedIds(prev => {
      const next = new Set(prev);
      allIds.forEach(id => allSelected ? next.delete(id) : next.add(id));
      return next;
    });
  };

  const handleRepairAddress = async () => {
    const ids = Array.from(selectedIds);
    if (ids.length === 0) return;
    setIsEnriching(true);
    setEnrichProgress({ current: 0, total: ids.length });
    try {
      // Call discover-asian-restaurants in repair mode with specific IDs
      const batchSize = 10;
      let repaired = 0;
      for (let i = 0; i < ids.length; i += batchSize) {
        const batch = ids.slice(i, i + batchSize);
        const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
          body: { mode: "repair", restaurant_ids: batch, limit: batch.length },
        });
        if (error) throw error;
        repaired += data?.fixed || 0;
        setEnrichProgress({ current: Math.min(i + batchSize, ids.length), total: ids.length });
        if (i + batchSize < ids.length) await new Promise(r => setTimeout(r, 1000));
      }
      toast.success(`已修复 ${repaired} 条记录（名称+地址+坐标）`);
    } catch (e: any) {
      toast.error("修复失败: " + (e?.message || JSON.stringify(e)));
    } finally {
      setIsEnriching(false);
      setSelectedIds(new Set());
      await runCheck("all");
    }
  };

  const getIssueLabel = (type: string) => {
    switch (type) {
      case "too_short": return "地址过短";
      case "no_postal_code": return "缺邮编";
      case "incomplete_format": return "格式不完整";
      case "zero_coords": return "零坐标";
      case "has_brackets": return "含括号符号";
      case "generic_name": return "通用描述性名称";
      case "marketing_name": return "营销描述性名称";
      case "all_caps": return "全大写异常";
      case "special_chars": return "含特殊字符";
      case "looks_like_url": return "疑似网址";
      case "only_numbers": return "纯数字";
      default: return type || "";
    }
  };

  return (
    <div className="space-y-4">
      {!stats ? (
        <Card>
          <CardContent className="flex flex-col items-center py-10 gap-3">
            <FileWarning className="h-10 w-10 text-muted-foreground" />
            <p className="text-sm text-muted-foreground">点击下方按钮开始数据质量检查</p>
            <Button onClick={() => runCheck("all")} disabled={isLoading}>
              {isLoading ? <Loader2 className="mr-1.5 h-4 w-4 animate-spin" /> : <Shield className="mr-1.5 h-4 w-4" />}
              开始检查
            </Button>
          </CardContent>
        </Card>
      ) : (
        <>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            <StatsCard label="总记录" value={stats.total} color="text-foreground" />
            <StatsCard label="需修复" value={stats.invalid_name_count + stats.invalid_address_count + stats.zero_coords_count} color={(stats.invalid_name_count + stats.invalid_address_count + stats.zero_coords_count) > 0 ? "text-orange-600" : "text-emerald-600"} />
            <StatsCard label="重复记录" value={stats.duplicate_count} color={stats.duplicate_count > 0 ? "text-yellow-600" : "text-emerald-600"} />
            <StatsCard label="内容不完整" value={stats.incomplete_count} color={stats.incomplete_count > 0 ? "text-orange-600" : "text-emerald-600"} />
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            <StatsCard label="缺故事" value={stats.no_story_count} color={stats.no_story_count > 0 ? "text-orange-600" : "text-emerald-600"} />
            <StatsCard label="缺易经" value={stats.no_iching_count} color={stats.no_iching_count > 0 ? "text-purple-600" : "text-emerald-600"} />
            <StatsCard label="缺照片" value={stats.no_photo_count} color={stats.no_photo_count > 0 ? "text-blue-600" : "text-emerald-600"} />
            <StatsCard label="内容不完整" value={stats.incomplete_count} color={stats.incomplete_count > 0 ? "text-orange-600" : "text-emerald-600"} />
          </div>

          <Card>
            <CardContent className="pt-4 pb-3">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs text-muted-foreground">数据健康度</span>
                <span className="text-xs font-medium">
                  {stats.total > 0
                    ? `${(((stats.total - stats.invalid_address_count - stats.zero_coords_count) / stats.total) * 100).toFixed(1)}%`
                    : "N/A"}
                </span>
              </div>
              <Progress
                value={stats.total > 0 ? ((stats.total - stats.invalid_address_count - stats.zero_coords_count) / stats.total) * 100 : 0}
              />
            </CardContent>
          </Card>

          <Tabs value={activeTab} onValueChange={(v) => { setActiveTab(v); setSelectedIds(new Set()); }}>
            <div className="flex items-center justify-between">
              <TabsList className="flex-wrap h-auto">
                <TabsTrigger value="location" className="gap-1">
                  <Wrench className="h-3 w-3" /> 修复 ({stats.invalid_name_count + stats.invalid_address_count + stats.zero_coords_count})
                </TabsTrigger>
                <TabsTrigger value="duplicates" className="gap-1">
                  <Copy className="h-3 w-3" /> 重复 ({stats.duplicate_count})
                </TabsTrigger>
                <TabsTrigger value="incomplete" className="gap-1">
                  <AlertCircle className="h-3 w-3" /> 不完整 ({stats.incomplete_count})
                </TabsTrigger>
              </TabsList>
              <Button variant="outline" size="sm" onClick={() => runCheck("all")} disabled={isLoading}>
                <RefreshCw className={`mr-1 h-3 w-3 ${isLoading ? "animate-spin" : ""}`} /> 刷新
              </Button>
            </div>

            {/* Action bar */}
            {selectedIds.size > 0 && (
              <div className="flex items-center gap-2 mt-3 p-2 rounded-md bg-muted border">
                <span className="text-xs font-medium">已选 {selectedIds.size} 项</span>
                <div className="flex-1" />
                {activeTab === "duplicates" && (
                  <>
                    <Button variant="outline" size="sm" onClick={handleRepairAddress} disabled={isEnriching}>
                      {isEnriching ? <Loader2 className="mr-1 h-3 w-3 animate-spin" /> : <Wrench className="mr-1 h-3 w-3" />}
                      修复选中
                    </Button>
                    <Button variant="destructive" size="sm" onClick={handleDelete} disabled={isDeleting}>
                      {isDeleting ? <Loader2 className="mr-1 h-3 w-3 animate-spin" /> : <Trash2 className="mr-1 h-3 w-3" />}
                      删除选中（保留 ⭐）
                    </Button>
                  </>
                )}
                {activeTab === "incomplete" && (
                  <>
                    <Button variant="outline" size="sm" onClick={() => handleEnrichSelected("story")} disabled={isEnriching}>
                      <BookOpen className="mr-1 h-3 w-3" /> 补故事
                    </Button>
                    <Button variant="outline" size="sm" onClick={() => handleEnrichSelected("iching")} disabled={isEnriching}>
                      <Sparkles className="mr-1 h-3 w-3" /> 补易经
                    </Button>
                    <Button variant="outline" size="sm" onClick={() => handleEnrichSelected("photo")} disabled={isEnriching}>
                      <ImageIcon className="mr-1 h-3 w-3" /> 补照片
                    </Button>
                  </>
                )}
                {activeTab === "location" && (
                  <>
                    <Button variant="outline" size="sm" onClick={handleRepairAddress} disabled={isEnriching}>
                      {isEnriching ? <Loader2 className="mr-1 h-3 w-3 animate-spin" /> : <Wrench className="mr-1 h-3 w-3" />}
                      修复
                    </Button>
                    <Button variant="destructive" size="sm" onClick={handleDelete} disabled={isDeleting}>
                      {isDeleting ? <Loader2 className="mr-1 h-3 w-3 animate-spin" /> : <Trash2 className="mr-1 h-3 w-3" />}
                      删除选中
                    </Button>
                  </>
                )}
              </div>
            )}

            {isEnriching && enrichProgress.total > 0 && (
              <div className="mt-2 space-y-1">
                <Progress value={(enrichProgress.current / enrichProgress.total) * 100} />
                <p className="text-xs text-muted-foreground">修复中: {enrichProgress.current}/{enrichProgress.total}</p>
              </div>
            )}

            {activeTab === "incomplete" && !isEnriching && (
              <div className="mt-3 space-y-2">
                <div className="p-3 rounded-md border bg-muted/50 flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium">自动补全管线</p>
                    <p className="text-xs text-muted-foreground">自动为缺少内容的建筑批量补全故事、易经和照片</p>
                  </div>
                  <Button size="sm" onClick={() => handleEnrichSelected("auto")} disabled={isEnriching}>
                    <Play className="mr-1 h-3 w-3" /> 运行一批
                  </Button>
                </div>
                <div className="p-3 rounded-md border bg-primary/5 border-primary/20 flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium flex items-center gap-1.5">
                      <Star className="h-3.5 w-3.5 text-primary" /> 米其林个人IP生成
                    </p>
                    <p className="text-xs text-muted-foreground">为米其林餐厅批量生成主厨IP、招牌菜、黄帝内经解读</p>
                  </div>
                  <div className="flex gap-2">
                    <Button variant="outline" size="sm" onClick={async () => {
                      setIsEnriching(true);
                      try {
                        const { data, error } = await supabase.functions.invoke("generate-michelin-ip", {
                          body: { batch_size: 3, dry_run: true },
                        });
                        if (error) throw error;
                        toast.info(`预览: 找到 ${data?.processed || 0} 家待处理`, {
                          description: data?.results?.map((r: any) => `${r.name}: ${r.chef_name || r.status}`).join('\n'),
                          duration: 8000,
                        });
                      } catch (e) {
                        toast.error("预览失败: " + (e instanceof Error ? e.message : String(e)));
                      } finally {
                        setIsEnriching(false);
                      }
                    }} disabled={isEnriching}>
                      预览
                    </Button>
                    <Button size="sm" onClick={async () => {
                      setIsEnriching(true);
                      setEnrichProgress({ current: 0, total: 5 });
                      try {
                        const { data, error } = await supabase.functions.invoke("generate-michelin-ip", {
                          body: { batch_size: 5 },
                        });
                        if (error) throw error;
                        toast.success(`IP生成完成: ${data?.succeeded || 0} 成功, ${data?.failed || 0} 失败`);
                      } catch (e) {
                        toast.error("生成失败: " + (e instanceof Error ? e.message : String(e)));
                      } finally {
                        setIsEnriching(false);
                        await runCheck("all");
                      }
                    }} disabled={isEnriching}>
                      <Star className="mr-1 h-3 w-3" /> 生成一批 (5)
                    </Button>
                  </div>
                </div>

                {/* Signature dish extractor */}
                <div className="p-3 rounded-md border bg-amber-50/50 border-amber-200/60 flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium flex items-center gap-1.5">
                      <Star className="h-3.5 w-3.5 text-amber-600" /> 招牌菜抓取（含图片）
                    </p>
                    <p className="text-xs text-muted-foreground">
                      从米其林指南链接（或官网）抓取 1 道招牌菜及照片。无链接餐厅会被跳过并列出。
                    </p>
                  </div>
                  <div className="flex gap-2">
                    <Button variant="outline" size="sm" onClick={async () => {
                      setIsEnriching(true);
                      try {
                        const { data, error } = await supabase.functions.invoke("batch-extract-signature-dishes", {
                          body: { batch_size: 5, dry_run: true },
                        });
                        if (error) throw error;
                        toast.info(`待处理 ${data?.eligible_count || 0} 家，缺链接 ${data?.skipped_missing_url_count || 0} 家`, {
                          description: data?.skipped_missing_url?.length
                            ? `缺链接示例:\n${data.skipped_missing_url.slice(0, 5).map((r: any) => r.name).join('\n')}`
                            : undefined,
                          duration: 10000,
                        });
                      } catch (e) {
                        toast.error("预览失败: " + (e instanceof Error ? e.message : String(e)));
                      } finally {
                        setIsEnriching(false);
                      }
                    }} disabled={isEnriching}>
                      预览
                    </Button>
                    <Button size="sm" onClick={async () => {
                      setIsEnriching(true);
                      setEnrichProgress({ current: 0, total: 5 });
                      try {
                        const { data, error } = await supabase.functions.invoke("batch-extract-signature-dishes", {
                          body: { batch_size: 5 },
                        });
                        if (error) throw error;
                        const skip = data?.skipped_missing_url_count || 0;
                        toast.success(`完成: ${data?.succeeded || 0} 成功 / ${data?.failed || 0} 失败 / 剩余 ${data?.remaining_eligible || 0}`, {
                          description: skip > 0 ? `⚠️ ${skip} 家缺米其林链接，已跳过` : undefined,
                          duration: 10000,
                        });
                      } catch (e) {
                        toast.error("抓取失败: " + (e instanceof Error ? e.message : String(e)));
                      } finally {
                        setIsEnriching(false);
                        await runCheck("all");
                      }
                    }} disabled={isEnriching}>
                      <Star className="mr-1 h-3 w-3" /> 抓一批 (5)
                    </Button>
                  </div>
                </div>
              </div>
            )}


            {/* Repair tab (names + address + coords) */}
            <TabsContent value="location" className="mt-3 space-y-2">
              {repairIssueTypeCounts.size > 1 && (
                <div className="flex flex-wrap gap-1.5">
                  <Badge
                    variant={repairFilter === null ? "default" : "outline"}
                    className="cursor-pointer text-xs"
                    onClick={() => { setRepairFilter(null); setSelectedIds(new Set()); }}
                  >
                    全部 ({repairIssues.length})
                  </Badge>
                  {Array.from(repairIssueTypeCounts.entries())
                    .sort((a, b) => b[1] - a[1])
                    .map(([type, count]) => (
                      <Badge
                        key={type}
                        variant={repairFilter === type ? "default" : "outline"}
                        className="cursor-pointer text-xs"
                        onClick={() => { setRepairFilter(type); setSelectedIds(new Set()); }}
                      >
                        {getIssueLabel(type)} ({count})
                      </Badge>
                    ))}
                </div>
              )}
              <IssueList
                items={filteredRepairIssues}
                selectedIds={selectedIds}
                toggleId={toggleId}
                toggleAll={() => toggleAll(filteredRepairIssues)}
                tab="location"
                getIssueLabel={getIssueLabel}
              />
            </TabsContent>

            {/* Incomplete tab */}
            <TabsContent value="incomplete" className="mt-3">
              <IssueList
                items={incomplete}
                selectedIds={selectedIds}
                toggleId={toggleId}
                toggleAll={() => toggleAll(incomplete)}
                tab="incomplete"
                getIssueLabel={getIssueLabel}
              />
            </TabsContent>

            {/* Duplicates tab uses grouped view */}
            <TabsContent value="duplicates" className="mt-3">
              <DuplicateGroupList
                groups={duplicateGroups}
                keptIds={keptIds}
                selectedIds={selectedIds}
                toggleId={toggleId}
                selectAllExceptKept={selectAllDuplicatesExceptKept}
              />
            </TabsContent>
          </Tabs>
        </>
      )}

      <AlertDialog open={confirmDialog.open} onOpenChange={(open) => setConfirmDialog(prev => ({ ...prev, open }))}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{confirmDialog.title}</AlertDialogTitle>
            <AlertDialogDescription>{confirmDialog.description}</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>取消</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDialog.onConfirm} className="bg-destructive text-destructive-foreground hover:bg-destructive/90">
              确认删除
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

// ─── Duplicate Group List ───────────────────────────────────────────────────
function DuplicateGroupList({
  groups,
  keptIds,
  selectedIds,
  toggleId,
  selectAllExceptKept,
}: {
  groups: DuplicateGroup[];
  keptIds: Set<string>;
  selectedIds: Set<string>;
  toggleId: (id: string) => void;
  selectAllExceptKept: () => void;
}) {
  const totalItems = groups.reduce((s, g) => s + g.items.length, 0);
  const removableCount = groups.reduce((s, g) => s + g.items.length - 1, 0);

  if (groups.length === 0) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center py-8 gap-2">
          <CheckCircle2 className="h-8 w-8 text-emerald-500" />
          <p className="text-sm text-muted-foreground">没有发现重复 ✨</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" onClick={selectAllExceptKept}>
              <Trash2 className="mr-1 h-3 w-3" />
              选中全部重复（{removableCount} 条，每组保留 1 个）
            </Button>
          </div>
          <div className="text-xs text-muted-foreground">
            {groups.length} 组 · {totalItems} 条记录 · ⭐ = 建议保留
          </div>
        </div>
      </CardHeader>
      <CardContent className="p-0">
        <ScrollArea className="h-[50vh]">
          {groups.map((group, gi) => (
            <div key={group.key} className={gi > 0 ? "border-t-2 border-primary/10" : ""}>
              {/* Group header */}
              <div className="px-4 py-1.5 bg-muted/70 text-xs font-medium text-muted-foreground flex items-center gap-2 sticky top-0 z-10">
                <Copy className="h-3 w-3" />
                {group.items[0]?.name_en || group.items[0]?.name} — {group.items.length} 条记录
              </div>
              {/* Group items */}
              <div className="divide-y">
                {group.items.map(item => {
                  const isKept = keptIds.has(item.id);
                  return (
                    <div
                      key={item.id}
                      className={`flex items-start gap-3 px-4 py-2.5 cursor-pointer transition-colors ${
                        isKept
                          ? "bg-emerald-50/50 dark:bg-emerald-900/10 hover:bg-emerald-50 dark:hover:bg-emerald-900/20"
                          : "hover:bg-muted/50"
                      }`}
                      onClick={() => toggleId(item.id)}
                    >
                      <Checkbox checked={selectedIds.has(item.id)} className="mt-0.5" />
                      <div className="flex-1 min-w-0">
                        <div className="font-medium text-sm flex items-center gap-1.5">
                          {isKept && <Star className="h-3.5 w-3.5 text-amber-500 flex-shrink-0 fill-amber-500" />}
                          <span className="truncate">{item.name_en || item.name}</span>
                          {item.template && (
                            <Badge variant="outline" className="text-[9px] h-4 px-1">
                              {item.template === "landmark" ? "🏛️" : "🍽️"} {item.template}
                            </Badge>
                          )}
                          {isKept && (
                            <Badge className="text-[9px] h-4 bg-emerald-100 text-emerald-700 dark:bg-emerald-900 dark:text-emerald-300 border-0">
                              建议保留
                            </Badge>
                          )}
                        </div>
                        <div className="text-xs text-muted-foreground flex items-center gap-1 mt-0.5">
                          <MapPin className="h-3 w-3 flex-shrink-0" />
                          <span className="truncate">{item.address}</span>
                        </div>
                        <div className="flex items-center gap-1.5 mt-0.5">
                          {item.google_place_id && (
                            <Badge variant="outline" className="text-[9px] h-4 border-emerald-300 text-emerald-600">PID</Badge>
                          )}
                          {item.image_url && (
                            <Badge variant="outline" className="text-[9px] h-4 border-blue-300 text-blue-600">有图</Badge>
                          )}
                          <span className="text-[10px] text-muted-foreground">
                            {item.created_at ? new Date(item.created_at).toLocaleDateString() : ""}
                          </span>
                        </div>
                      </div>
                      <a
                        href={`/admin/restaurants`}
                        onClick={e => e.stopPropagation()}
                        className="text-muted-foreground hover:text-primary"
                      >
                        <ExternalLink className="h-3.5 w-3.5" />
                      </a>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </ScrollArea>
      </CardContent>
    </Card>
  );
}

// ─── Flat Issue List (for address/coords/incomplete) ────────────────────────
function IssueList({
  items,
  selectedIds,
  toggleId,
  toggleAll,
  tab,
  getIssueLabel,
}: {
  items: DataIssue[];
  selectedIds: Set<string>;
  toggleId: (id: string) => void;
  toggleAll: () => void;
  tab: string;
  getIssueLabel: (type: string) => string;
}) {
  if (items.length === 0) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center py-8 gap-2">
          <CheckCircle2 className="h-8 w-8 text-emerald-500" />
          <p className="text-sm text-muted-foreground">没有发现问题 ✨</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader className="pb-2">
        <div className="flex items-center gap-2">
          <Checkbox
            checked={items.every(i => selectedIds.has(i.id))}
            onCheckedChange={toggleAll}
          />
          <CardTitle className="text-sm">
            全选 ({items.filter(i => selectedIds.has(i.id)).length}/{items.length})
          </CardTitle>
        </div>
      </CardHeader>
      <CardContent className="p-0">
        <ScrollArea className="h-[50vh]">
          <div className="divide-y">
            {items.map(item => (
              <div
                key={item.id}
                className="flex items-start gap-3 px-4 py-2.5 hover:bg-muted/50 cursor-pointer transition-colors"
                onClick={() => toggleId(item.id)}
              >
                <Checkbox checked={selectedIds.has(item.id)} className="mt-0.5" />
                <div className="flex-1 min-w-0">
                  <div className="font-medium text-sm flex items-center gap-1.5">
                    <span className="truncate">{item.name_en || item.name}</span>
                    {item.template && (
                      <Badge variant="outline" className="text-[9px] h-4 px-1">
                        {item.template === "landmark" ? "🏛️" : "🍽️"} {item.template}
                      </Badge>
                    )}
                  </div>
                  <div className="text-xs text-muted-foreground flex items-center gap-1 mt-0.5">
                    <MapPin className="h-3 w-3 flex-shrink-0" />
                    <span className="truncate">{item.address}</span>
                  </div>
                  {(tab === "address" || tab === "location") && item.issue_type && (
                    <div className="flex gap-1 mt-0.5 flex-wrap">
                      <Badge variant="destructive" className="text-[9px] h-4">
                        {getIssueLabel(item.issue_type)}
                      </Badge>
                      {(item.lat === 0 && item.lng === 0) && item.issue_type !== 'zero_coords' && (
                        <Badge variant="destructive" className="text-[9px] h-4">
                          零坐标
                        </Badge>
                      )}
                    </div>
                  )}
                  {tab === "location" && !item.issue_type && item.lat === 0 && item.lng === 0 && (
                    <Badge variant="destructive" className="text-[9px] mt-0.5 h-4">
                      零坐标
                    </Badge>
                  )}
                  {tab === "location" && (
                    <span className="text-[10px] text-muted-foreground mt-0.5 block">
                      坐标: ({item.lat}, {item.lng})
                    </span>
                  )}
                  {tab === "incomplete" && (
                    <div className="flex gap-1 mt-0.5 flex-wrap">
                      {item.missing_story && <Badge variant="outline" className="text-[9px] h-4 border-orange-300 text-orange-600">缺故事</Badge>}
                      {item.missing_iching && <Badge variant="outline" className="text-[9px] h-4 border-purple-300 text-purple-600">缺易经</Badge>}
                      {item.missing_photo && <Badge variant="outline" className="text-[9px] h-4 border-blue-300 text-blue-600">缺照片</Badge>}
                      {item.missing_description && <Badge variant="outline" className="text-[9px] h-4 border-muted-foreground text-muted-foreground">缺描述</Badge>}
                    </div>
                  )}
                </div>
                <a
                  href={`/admin/restaurants`}
                  onClick={e => e.stopPropagation()}
                  className="text-muted-foreground hover:text-primary"
                >
                  <ExternalLink className="h-3.5 w-3.5" />
                </a>
              </div>
            ))}
          </div>
        </ScrollArea>
      </CardContent>
    </Card>
  );
}

function StatsCard({ label, value, color }: { label: string; value: number; color: string }) {
  return (
    <Card>
      <CardContent className="pt-3 pb-2 px-3 text-center">
        <div className={`text-xl font-bold ${color}`}>{value}</div>
        <div className="text-[10px] text-muted-foreground">{label}</div>
      </CardContent>
    </Card>
  );
}
